const used = new Set<string>();
const persistViaBroker = (token: string) => token;
export function refresh(token: string) {
  if (used.has(token)) throw new Error('replay');
  used.add(token);
  const replacement = token + '-rotated';
  persistViaBroker(replacement);
  return { token: replacement, familyId: 'family-1' };
}

